import{_ as e,o as a,c as o,Q as r}from"./chunks/framework.6d94f49f.js";const m=JSON.parse('{"title":"问题总结","description":"","frontmatter":{},"headers":[],"relativePath":"数据库/Mysql/问题/问题.md","filePath":"数据库/Mysql/问题/问题.md","lastUpdated":1700319152000}'),t={name:"数据库/Mysql/问题/问题.md"},n=r('<h1 id="问题总结" tabindex="-1">问题总结 <a class="header-anchor" href="#问题总结" aria-label="Permalink to &quot;问题总结&quot;">​</a></h1><h3 id="_1-where-后面的列顺序是不是要符合最左原则" tabindex="-1">1.Where 后面的列顺序是不是要符合最左原则？ <a class="header-anchor" href="#_1-where-后面的列顺序是不是要符合最左原则" aria-label="Permalink to &quot;1.Where 后面的列顺序是不是要符合最左原则？&quot;">​</a></h3><p>Where a=1 and b=2 等价于 Where b=2 and a=1</p><p>最左原则指的是索引顺序，不是谓词顺序，以上两个条件都匹配( a,b) 复合索引。</p><h3 id="_2-join-的顺序是否指定左边为驱动表" tabindex="-1">2.Join 的顺序是否指定左边为驱动表？ <a class="header-anchor" href="#_2-join-的顺序是否指定左边为驱动表" aria-label="Permalink to &quot;2.Join 的顺序是否指定左边为驱动表？&quot;">​</a></h3><p>Inner Join场景下，在执行计划中按统计信息的预估自动选中驱动表，Left Join ,Right Join 时左右写的顺序才有显式意义。</p><h3 id="_3-业务上有随机返回的需求-能否用order-by-rand" tabindex="-1">3.业务上有随机返回的需求，能否用order by rand() <a class="header-anchor" href="#_3-业务上有随机返回的需求-能否用order-by-rand" aria-label="Permalink to &quot;3.业务上有随机返回的需求，能否用order by rand()&quot;">​</a></h3><p>一般不建议，如果结果集非常小，勉强可用，但结果集大时由于随机数排序，会产生Sort操作甚至溢出到磁盘，有很大性</p><p>能损耗，此类需求可以考虑伪随机算法。</p><h3 id="_4-delete数据之后-为什么磁盘空间占用反而大了" tabindex="-1">4.Delete数据之后，为什么磁盘空间占用反而大了？ <a class="header-anchor" href="#_4-delete数据之后-为什么磁盘空间占用反而大了" aria-label="Permalink to &quot;4.Delete数据之后，为什么磁盘空间占用反而大了？&quot;">​</a></h3><p>Delete数据并不能清理数据文件空间，反而会导致Undo,Binlog文件的增长，使用Optimize收缩。</p><h3 id="_5-binlog是否一定要row格式" tabindex="-1">5.Binlog是否一定要Row格式？ <a class="header-anchor" href="#_5-binlog是否一定要row格式" aria-label="Permalink to &quot;5.Binlog是否一定要Row格式？&quot;">​</a></h3><p>在主从场景下，Binlog使用Row格式是为了保证主从数据一致性。</p><p>单机场景下，Binlog做为增长数据备份使用，同时也包括一些语句级数据恢复的功能。</p><h3 id="_6-死锁、阻塞的区别" tabindex="-1">6.死锁、阻塞的区别 <a class="header-anchor" href="#_6-死锁、阻塞的区别" aria-label="Permalink to &quot;6.死锁、阻塞的区别&quot;">​</a></h3><p>通常说的阻塞，主要是由于锁获取不到，产生的请求被阻塞，一般需要手动解锁(Kill或等待)。</p><p>死锁不等于阻塞，虽然死锁中阻塞是必现的，但是会自动回滚事务解锁，不用手动处理，但需要业务判断语句逻辑。</p><p>以上两种情况都是由于业务侧逻辑出现，并非内核原因。</p><h3 id="_7-做ddl时是否会锁表" tabindex="-1">7.做DDL时是否会锁表 <a class="header-anchor" href="#_7-做ddl时是否会锁表" aria-label="Permalink to &quot;7.做DDL时是否会锁表&quot;">​</a></h3><p>所有的DDL都需要锁表，只是操作顺序和操作获取时间的问题。</p><p>详情参考官方文档：<a href="https://dev.mysql.com/doc/refman/5.6/en/innodb-online-ddl-operations.html" target="_blank" rel="noreferrer">https://dev.mysql.com/doc/refman/5.6/en/innodb-online-ddl-operations.html</a></p>',21),l=[n];function i(d,h,s,_,p,c){return a(),o("div",null,l)}const f=e(t,[["render",i]]);export{m as __pageData,f as default};
